/**
 * Character Metadata Utilities
 *
 * Provides pinyin and word examples for Chinese characters.
 * Pinyin is generated by the pinyin-pro library which covers
 * all CJK characters across Unicode planes.
 * Word examples come from a built-in curated dataset.
 */

import { pinyin, polyphonic } from 'pinyin-pro'
import type { WordBook } from '../core/types'

interface CharInfo {
  pinyin: string
  words: string[]
}

