/**
 * Error thrown by validation functions when user input is invalid.
 * Distinguishable from system errors (IndexedDB, network) so callers
 * can silently skip validation failures while surfacing real problems.
 */
export class ValidationError extends Error {
  constructor(message: string) {
    super(message)
    this.name = 'ValidationError'
  }
}

/**
 * Check whether a single character is a Chinese (Han) character.
 * Uses Unicode property escapes to cover all CJK planes,
 * including Extension A–G in supplementary planes.
 */
export function isChineseChar(char: string): boolean {
  if (!char || char.length === 0) return false
  // \p{Script=Han} matches all Han characters across all Unicode planes
  return /^\p{Script=Han}$/u.test(char)
}

/**
 * Validate that a character can be added to a word book.
 * Throws if the character is not Chinese or already exists in the book.
 */
export function validateAddChar(character: string, wordBook: WordBook): void {
  if (!isChineseChar(character)) {
    throw new ValidationError(`"${character}" 不是汉字，不能添加到生字本`)
  }
  if (wordBook.characters.includes(character)) {
    throw new ValidationError(`"${character}" 已在生字本中，不能重复添加`)
  }
}

/**
 * Get pinyin for a single Chinese character using pinyin-pro library.
 * For polyphonic characters (多音字), returns all readings joined by " · ".
 * Covers all CJK characters — no more '?' fallback.
 */
export function getPinyin(char: string): string {
  const readings = polyphonic(char)[0]
  if (!readings) return pinyin(char) // fallback for non-Han chars
  return readings.split(' ').join(' · ')
}

/**
 * Get character information (pinyin + words).
 * Pinyin is always generated via pinyin-pro. Polyphonic characters
 * show all readings separated by " · ".
 * Words come from the built-in curated dataset.
 */
export function getCharInfo(char: string): CharInfo {
  return {
    pinyin: getPinyin(char),
    words: WORD_DATABASE[char] ?? [],
  }
}

/**
 * Get example words for a character.
 */
export function getWords(char: string): string[] {
  return WORD_DATABASE[char] ?? []
}
